data.value:
decimal totalChicksPlaced = 0;
decimal totalCobbField = 0;
decimal totalRossField = 0;
decimal totalOtherField = 0;
decimal totalWeekMort = 0;
decimal totalCumDep = 0;
decimal totalSat = 0;
decimal totalSun = 0;
decimal totalMon = 0;
decimal totalTue = 0;
decimal totalWed = 0;
decimal totalThru = 0;
decimal totalFri = 0;
private void Detail_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
        // Get ChickPlaced value
    object chicksObj = GetCurrentColumnValue("ChickPlaced");
    decimal chickPlaced = 0;

    if (chicksObj != null && chicksObj != DBNull.Value)
    {
        chickPlaced = Convert.ToDecimal(chicksObj);
        totalChicksPlaced += chickPlaced;
    }

    // Calculate @CobbField: if tFrGroupBreedID = 2 then ChickPlaced else 0
    object breedIdObj = GetCurrentColumnValue("tFrGroupBreedID");
    decimal cobbFieldValue = 0;

    if (breedIdObj != null && breedIdObj != DBNull.Value)
    {
        int breedId = Convert.ToInt32(breedIdObj);

        // @CobbField logic: if tFrGroupBreedID = 2 then ChickPlaced else 0
        if (breedId == 2)
        {
            cobbFieldValue = chickPlaced;
        }
    }

    totalCobbField += cobbFieldValue;



     // Helper function to get int values
    int GetInt(string fieldName)
    {
        object value = GetCurrentColumnValue(fieldName);
        if (value == null || value == DBNull.Value)
            return 0;
        return Convert.ToInt32(value);
    }


    // Calculate @RossField based on tFrGroupBreedID = 1
    int breedId = GetInt("tFrGroupBreedID");
    decimal rossFieldValue = (breedId == 1) ? chickPlaced : 0;
    totalRossField += rossFieldValue;




    // Calculate @OtherField: if tFrGroupBreedID is NOT 1 AND NOT 2 then ChickPlaced else 0
    int breedId = GetInt("tFrGroupBreedID");

    // Check if breedId is neither 1 nor 2
    if (breedId != 1 && breedId != 2)
    {
        totalOtherField += chickPlaced;
    }

        // Helper function to safely convert values
    decimal SafeConvert(object value)
    {
        if (value == null || value == DBNull.Value || string.IsNullOrEmpty(value.ToString()))
            return 0;
        return Convert.ToDecimal(value);
    }


    // Calculate @WeekMortTotal for this row: Sat + Sun + Mon + Tue + Wed + Thru + Fri
    decimal weekMortTotal = 
        SafeConvert(GetCurrentColumnValue("Sat")) +
        SafeConvert(GetCurrentColumnValue("Sun")) +
        SafeConvert(GetCurrentColumnValue("Mon")) +
        SafeConvert(GetCurrentColumnValue("Tue")) +
        SafeConvert(GetCurrentColumnValue("Wed")) +
        SafeConvert(GetCurrentColumnValue("Thru")) +
        SafeConvert(GetCurrentColumnValue("Fri"));

    // Accumulate weekly mortality
    totalWeekMort += weekMortTotal;

        // Accumulate CumTotalDep
    totalCumDep += SafeConvert(GetCurrentColumnValue("CumTotalDep"));
    // Accumulate Saturday mortality
    totalSat += SafeConvert(GetCurrentColumnValue("Sat"));
    // Accumulate Sunday mortality
    totalSun += SafeConvert(GetCurrentColumnValue("Sun"));
    // Accumulate Monday mortality
    totalMon += SafeConvert(GetCurrentColumnValue("Mon"));
    // Accumulate Tuesday mortality
    totalTue += SafeConvert(GetCurrentColumnValue("Tue"));
        // Accumulate Wednesday mortality
    totalWed += SafeConvert(GetCurrentColumnValue("Wed"));
     // Accumulate Thursday (Thru) mortality
    totalThru += SafeConvert(GetCurrentColumnValue("Thru"));
        // Accumulate Friday mortality
    totalFri += SafeConvert(GetCurrentColumnValue("Fri"));
    }

private void xrLabel7_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
        XRTableCell cell = sender as XRTableCell;

    // Get RTL parameter
    bool isRTL = false;
    if (Report.Parameters["IsRTL"] != null)
    {
        isRTL = Convert.ToBoolean(Report.Parameters["IsRTL"].Value);
    }

    // Calculate and display
    if (totalChicksPlaced > 0)
    {
        decimal result = (totalCobbField / totalChicksPlaced) * 100.0m;
        string formattedResult = result.ToString("N2");

        if (isRTL)
        {
            cell.Text = "كوب%: " + formattedResult;
        }
        else
        {
            cell.Text = "COBB%: " + formattedResult;
        }

    }
    else
    {
        if (isRTL)
        {
            cell.Text = "كوب%: 0.00";
        }
        else
        {
            cell.Text = "COBB%: 0.00";
        }
    }
}

