private void xrTableCell44_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

// Get values from the data source
decimal chickPlaced = Convert.ToDecimal(GetCurrentColumnValue("ChickPlaced") ?? 0);
decimal sat = Convert.ToDecimal(GetCurrentColumnValue("Sat") ?? 0);
decimal sun = Convert.ToDecimal(GetCurrentColumnValue("Sun") ?? 0);
decimal mon = Convert.ToDecimal(GetCurrentColumnValue("Mon") ?? 0);
decimal tue = Convert.ToDecimal(GetCurrentColumnValue("Tue") ?? 0);
decimal wed = Convert.ToDecimal(GetCurrentColumnValue("Wed") ?? 0);
decimal thru = Convert.ToDecimal(GetCurrentColumnValue("Thru") ?? 0);
decimal fri = Convert.ToDecimal(GetCurrentColumnValue("Fri") ?? 0);

// Calculate @WeekMortTotal = Sat + Sun + Mon + Tue + Wed + Thru + Fri
decimal weekMortTotal = sat + sun + mon + tue + wed + thru + fri;

if (chickPlaced > 0)
{
    // Calculate: (@WeekMortTotal / ChickPlaced) * 100
    // This gives weekly mortality percentage
    decimal result = (weekMortTotal / chickPlaced) * 100.0m;
    cell.Text = result.ToString("N2"); // Formats to 2 decimal places
}
else
{
    cell.Text = "0.00";
}
}

private void xrTableCell53_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

// Get values from the data source
decimal chickPlaced = Convert.ToDecimal(GetCurrentColumnValue("ChickPlaced") ?? 0);
decimal cumTotalDep = Convert.ToDecimal(GetCurrentColumnValue("CumTotalDep") ?? 0);

if (chickPlaced > 0)
{
    // Calculate: (CumTotalDep / ChickPlaced) * 100
    // This gives cumulative total depletion percentage
    decimal result = (cumTotalDep / chickPlaced) * 100.0m;
    cell.Text = result.ToString("N2"); // Formats to 2 decimal places
}
else
{
    cell.Text = "0.00";
}
}

private void xrTableCell58_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
        XRTableCell cell = sender as XRTableCell;

    if (totalChicksPlaced > 0)
    {
        decimal totalWeekMort = totalSat + totalSun + totalMon + totalTue + totalWed + totalThu + totalFri;
        decimal result = (totalWeekMort / totalChicksPlaced) * 100.0m;

        cell.Text = result.ToString("N2") ;

    }
    else
    {
        cell.Text = "0.00";
    }
}

